var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"좌현! 10시 방향! 적 기동부대, 제 5차 공세 개시! 고속접근!","JPN":"左舷！　10時方向！\\n敵の機動部隊、第5次攻勢を開始！　高速接近中！","ENG":"Port side! 10 o' clock! Enemy unit commencing 5th attack wave! Incoming rapidly!","TWN":"左舷！10點鐘方向！敵人的機動部隊展開第五次攻勢！高速接近中！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"정면! 적 본영으로부터 네임드 제 3종 침식체 전진 중! 식별명...... <color=#ffd34c>오거</color>!","JPN":"正面！　敵の本営よりネームド第3種の侵食体が前進中！\\n識別名……<color=#ffd34c>オーガ</color>！","ENG":"Towards the bow! Category 3 C.O advancing from enemy formation! Code name... <color=#ffd34c>Ogre</color>!","TWN":"正面！敵人大本營中出現第三種侵蝕體！識別為……<color=#ffd34c>食人魔</color>！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"리플레이서 나이트, 궤도 추적 실패! 위치 확인 불가! 주의 요망!","JPN":"リプレイサー・ナイト、軌道追跡に失敗！\\n位置確認できません！　ご注意を！","ENG":"Failed to track the Replacer Knight's trajectory! Bogey position unknown! Extreme caution advised!","TWN":"克隆·騎士，軌道追蹤失敗！無法確定位置！請各位嚴加提防！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"알트 소대! 현 위치를 유지할 경우 20초 후에 포위됩니다! 즉시 이동하세요!","JPN":"アルト小隊！\\n現在の位置を維持した場合、20秒後に取り囲まれます！　すぐに移動してください！","ENG":"ALT Squad! You’ll be surrounded in 20 seconds if you maintain your current position! Get out of there, now!","TWN":"阿爾特小隊！待在目前位置20秒後會被包圍！馬上移動！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BOOM"},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"똑똑, 안녕하세요, 여러분. 많이 바쁘시죠?","JPN":"トントン！　こんにちは。皆さん、お忙しいですよね？","ENG":"Knock, knock! Hi everyone. Got your hands full, huh?","TWN":"咚咚，你們好啊，各位。你們現在很忙嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_SMALL"},{"id":"L10_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어......? 여, 여긴 어떻게 들어온 거에요?","JPN":"えっ……？　ど、どうやってここに入ったんですか？","ENG":"Huh? H-how did you get in here?","TWN":"呃……？妳、妳是怎麼進到這裡來的？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"함교는 외부인 출입 금지라고요!","JPN":"艦橋は部外者立ち入り禁止です！","ENG":"The bridge is for authorized personnel only!","TWN":"艦橋是禁止外人出入的！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 조금 신경 쓰이는 게 있어서요.","JPN":"ははは、少し気になることがあって。","ENG":"Haha, there was just something bothering me, you see.","TWN":"哈哈，我只是有件好奇的事情。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"잠깐만 확인하고 돌아갈게요.","JPN":"ちょっとだけ確認して帰ります。","ENG":"I’ll be just a minute. Just need to check something.","TWN":"我確認一下就走。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아, 아니! 뭘 맘대로 앉는 거에요?!","JPN":"い、いや！　何を勝手に座ってるんですか？","ENG":"W-what?! Who said you can have a seat there?!","TWN":"啊，不行！妳怎麼自己就坐下了？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"이봐요, 내 말 듣고 있어요? ......그거 건드리면 안 된다고!","JPN":"ちょっと、私の話聞いてますか？　それ触っちゃダメですって！","ENG":"Hey, are you even listening to me? You shouldn’t touch that!","TWN":"喂，妳有在聽我說話嗎？……不能碰那個！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"......레나 양? 지금 어디에 한눈 팔고 있죠?","JPN":"……レナ？　何よそ見してるんですか？","ENG":"Lena? What’s keeping you distracted?","TWN":"……蕾娜小姐，妳在分什麼心？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"지금 같은 상황에 저 혼자 전투지원을 맡는 건 무리라고요!","JPN":"こんな状況で私一人で戦闘支援をするなんて、無理ですよ！","ENG":"You know I can't provide combat support all by myself in a situation like this!","TWN":"現在這種情況，我沒辦法一個人擔任戰鬥支援！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아......? 그, 그건 그런데......","JPN":"え……？　そ、それはそうだけど……","ENG":"Oh... I-I know, but...","TWN":"啊……？沒、沒錯，可是……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"바쁘신 것 같은데 일 보세요. 전 안 도와주셔도 돼요.","JPN":"お忙しいようなので、仕事に戻ってください。私はお手伝い不要ですよ。","ENG":"Looks like your friend could use a hand. Please go ahead. Don’t mind me. I don’t need your help.","TWN":"你們好像很忙的樣子，我是不會幫忙的喔。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"누가 돕는대?!","JPN":"誰が手伝うって言った！？","ENG":"I wasn’t trying to help you!","TWN":"誰要妳幫忙了？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"......레나 양!","JPN":"……レナ！","ENG":"Lena!","TWN":"……蕾娜小姐！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아, 알았어! 간다고, 가!","JPN":"わ、わかった！　行くよ、行く！","ENG":"F-fine! Coming, coming!","TWN":"啊，知道了！我這就去。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"이봐, 당신! 금방 돌아올 테니까 쓸데없는 거 건드리지 말아요!","JPN":"ちょっと、あなたね！　すぐ戻るから、勝手に触らないでよね！","ENG":"Hey you! Don’t touch anything! I’ll be right back!","TWN":"喂，妳！立刻給我離開，不要隨便亂碰！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네이, 네이. 알겠습니다요.","JPN":"はい、はい。わかりました。","ENG":"Sure, sure. Whatever you say.","TWN":"好，好。我知道啦。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만...... 신경 쓰여서 참을 수가 없단 말이죠.","JPN":"でも……気になって仕方がないんです。","ENG":"But... I’ve got a mighty itch that needs to be scratched...","TWN":"但是……我好奇到忍不住了啊。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"역시......","JPN":"やっぱりね……","ENG":"Just as I thought...","TWN":"果然……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아아, 마이크 테스트. 마이크 테스트.","JPN":"あーあー、マイクテストです。","ENG":"Ah, ah. Mic test. Mic test.","TWN":"啊啊，麥克風測試。麥克風測試。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"잘 들리시나요?","JPN":"聞こえますか？","ENG":"Can you hear me?","TWN":"聽得到嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"잘 들립니다. 그런데 평소에 듣는 목소리가 아니네요?","JPN":"よく聞こえてます。でも普段聞いている声ではないですね。","ENG":"Loud and clear. But that’s not the voice we're used to.","TWN":"聽得到是聽得到，但好像不是平常聽到的聲音耶？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 나쁘다는 뜻은 아니에요. 듣기 좋아요.","JPN":"あ、悪い意味ではありません。聞きとりやすいですね。","ENG":"Oh, I’m not complaining. You sound lovely.","TWN":"啊，不是不好的意思。聲音很優美喔。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"헤헤, 뭐 목소리는 자신 있으니까요.","JPN":"へへ、まあ、声には自信がありますからね。","ENG":"Heh, I've always known I've got a pretty voice.","TWN":"嘿嘿，我對我的聲音很有自信哟。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"다, 다, 다, 당신! 전술 통신에 끼어들다니, 제정신이야?!","JPN":"あああ、あんた！　戦術通信に割り込むなんて、正気なの？","ENG":"Y-you! What do you think you're doing?! Butting in on the tactical comms?!","TWN":"妳妳妳，妳這個人！竟然介入戰術通信裡，妳瘋了嗎？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 바쁘신데 죄송하지만 한 가지만 물어보고 금방 닫을게요.","JPN":"あはは、お忙しいところすみません。一つだけ聞いて、すぐオフにしますね。","ENG":"Sorry to disturb you, but I’ll just ask a quick question.","TWN":"哈哈，在各位忙碌的時候抱歉打擾了，我問一個問題就走。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"잠시만요. 엇차!","JPN":"ちょっと待ってくださいね、ヨイショっと！","ENG":"One moment... Oopsie!","TWN":"等等喔。嘿咻！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_SWORD_SLASH_BIG_07"},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 이제 됐어요. 뭐가 궁금하시죠?","JPN":"ハハ、もう大丈夫ですよ。何が知りたいですか？","ENG":"Haha, okay, I’m ready. What do you want to know?","TWN":"哈哈，現在可以了。妳有什麼疑問呢？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_HIT_BIG"},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"지금 서윤 양의 위치를 알 수 있을까요?","JPN":"シズカさんの現在の居場所はわかりますか？","ENG":"Where is Ms. Seo right now?","TWN":"你們現在能知道徐芸小姐的位置嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"전술지도에는 표시가 안 되네요.","JPN":"戦術マップには表示されてませんね。","ENG":"I don't see her position on the tactical map.","TWN":"戰術地圖上沒有標記出來喔。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"흐음? 서윤 양이요......?","JPN":"ふむ、シズカさんですか……？","ENG":"Huh? Seo Yoon?","TWN":"嗯？徐芸小姐嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니 조금 전부터 안 보이는데......","JPN":"そういえばちょっと前から見当たらないですが……","ENG":"Now that you mention it, I haven’t seen her for a while...","TWN":"這麼一說，剛剛好像也沒看到她……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 끊어졌다.","JPN":"あ、途切れた。","ENG":"Oops, I hung up on him.","TWN":"啊，切斷了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아무것도 건들지 말랬잖아요!","JPN":"何も触るなって言ったでしょ！","ENG":"I told you not to touch anything!","TWN":"不是叫妳什麼都別碰了嗎！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 미안미안요. 하지만 이걸 꼭 확인하고 싶어서요.","JPN":"はは、ごめんなさい。でも、これをどうしても確認したくって。","ENG":"Haha, sorry. But I really wanted to check this.","TWN":"哈哈，抱歉抱歉。但是我非得確認這件事才行。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"대체 그게 뭔데......!?","JPN":"いったいなにを……！?","ENG":"What’s that?","TWN":"那到底是什麼……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......항법 시스템 접근 기록?","JPN":"……航法システムアクセス記録？","ENG":"Navigation system access log?","TWN":"……導航系統的連接記錄？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"여기 마지막에 보이시죠?","JPN":"ここ、最後の見えてますよね？","ENG":"See this here at the end?","TWN":"大家看這裡的最後一個。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"접. 근. 자. I. D. 서. 윤.","JPN":"アクセス主I.D.シズカ。","ENG":"Last... accessed... by... ID: Seo Yoon.","TWN":"訪.問.者.I.D.徐.芸."},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"덤으로 차원간 암호통신 기록까지.","JPN":"おまけに、次元間の暗号通信記録付きで。","ENG":"As a bonus, she even left a trace of her interdimensional crypto comm.","TWN":"再加上次元間的暗號通信記錄。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어라......? 이게 왜......?","JPN":"あれ……？　どういうこと……？","ENG":"Huh? Why’s this here?","TWN":"欸……？這是為什麼……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"항법 시스템은 보통 현장 요원들이 접근할 필요가 없는데?","JPN":"航法システムなら通常、現場メンバーはアクセスする必要がないのに。","ENG":"Field operatives usually don’t need access to the navigation system...","TWN":"通常現場的工作人員沒有必要連接導航系統的啊？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그러고 보니 조금 전에...... 함교에 있던 게......?","JPN":"そういえば、さっき……艦橋にいたのは……？","ENG":"Come to think of it... Yoon was just here moments ago...","TWN":"這麼說來，剛剛……在艦船裡的時候……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......설마?!","JPN":"……まさか！？","ENG":"Wait, is that why?!","TWN":"……該不會？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"딩동댕.","JPN":"ピンポ～ン。","ENG":"Bingo.","TWN":"叮咚叮咚。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"하, 하지만 서윤 양이 그럴 리가 없잖아요?","JPN":"で、でもシズカさんがそんなことするはずは……","ENG":"B-but she wouldn’t do such a thing, would she?","TWN":"但、但是徐芸小姐沒有理由這麼做啊？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"리플레이서에게 우리 쪽 좌표를 전달해 봐야 서윤 양에게 무슨 이득이 있나요?","JPN":"リプレイサーにこちらの座標を渡したところで、シズカさんに何の得が？","ENG":"What does she have to gain from sending our coordinates to the Replacers?","TWN":"告訴克隆集團我們的座標，徐芸小姐會有什麼好處嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭐, 그건 본인에게 들어 봐야겠지만......","JPN":"まあ、それは本人に聞いてみないとね。","ENG":"Well, we’ll have to hear that from herself...","TWN":"這個就得問本人才知道了……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"원한...... 이겠죠. 아마도.","JPN":"恨み……でしょうね。たぶん。","ENG":"But it’s probably some sort of... grudge. If I had to guess.","TWN":"有仇……吧，恐怕是這樣。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......원한?","JPN":"……恨み？","ENG":"A grudge?","TWN":"……有仇？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이곳에 잡아 둔 리플레이서 비숍이 서윤 양을 납치해서 목숨을 위협한 적이 있었죠?","JPN":"ここに拘束中の\\nリプレイサー・ビショップがシズカさんをさらって、\\n危険にさらされたことがありますよね？","ENG":"The Replacer Bishop you're keeping in custody here once abducted Ms. Seo and threatened her life, right?","TWN":"被關在這裡的克隆·大主教曾經綁架過徐芸小姐，還威脅過她的性命吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"만약 서윤 양이 그 일로 리플레이서 비숍에게 원한을 품었다면 지금이 아주 좋은 기회 아니겠어요?","JPN":"もしシズカさんがそのことで\\nリプレイサー・ビショップに恨みを持っているなら、\\nちょうど良いタイミングですよね。","ENG":"If she held a grudge against the Replacer Bishop from that, now would be the perfect opportunity to get payback, don't you think?","TWN":"如果徐芸小姐因此對克隆·大主教心懷仇恨，現在不就是個大好機會嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이런 난리통에 <color=#ffd34c>부수적 피해</color>가 발생하는 건 자연스러운 일이니까요.","JPN":"こんな大騒ぎ中に<color=#ffd34c>予期せぬ被害</color>が発生するのは自然なことですので。","ENG":"After all, <color=#ffd34c>collateral damage</color> is bound to happen in conflicts like this.","TWN":"因為在這種混亂的時候，就算產生一些<color=#ffd34c>附帶的損傷</color>不是很自然的事情嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"운이 좀 따라 준다면, 자기 손을 더럽히지 않고 처리할 수 있을지도 모르고요.","JPN":"運が良ければ、自分の手を汚さずに始末できるかもしれませんしね。","ENG":"With a little luck, she could get rid of her without soiling her own hands.","TWN":"運氣好一點的話，不用弄髒自己的手就可以把她處理掉了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그래서...... 서윤 양이 비숍을 해치려고 했다고요?","JPN":"それで……シズカさんがビショップを始末しようとしたと？","ENG":"So... Yoon was trying to harm the Bishop?","TWN":"所以……妳是說徐芸小姐想要加害克隆·大主教？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그런 이야긴 한 번도......","JPN":"そんな話は一度も……","ENG":"I’ve never heard of anything like that...","TWN":"從來沒想過會這樣……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 그럴 리가요.","JPN":"ははは、話すわけないでしょう。","ENG":"Haha, of course you haven’t.","TWN":"哈哈，確實呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"사람의 원한은 생각보다 깊어요.","JPN":"人の恨みは思ったより深いものです。","ENG":"People’s grudges go deeper than you’d think.","TWN":"人類的怨恨是比想像中還要很深的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......쉽게 사라지지 않죠.","JPN":"……簡単に消えたりはしません。","ENG":"They don’t fade away so easily.","TWN":"……而且不容易消除。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"전 경찰이라...... 그런 걸 아주 많이 봐 왔거든요.","JPN":"私は警察ですから……そういうものをたくさん見てきました。","ENG":"As a cop... I've seen many examples of this.","TWN":"因為我是一名警察……所以這種事情見多了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이런 것도 직업병으로 인정을 좀 해 주면 좋을 텐데. 하아~","JPN":"こういうのも職業病として認めてほしいのに。はあ～","ENG":"Comes with the job I guess. They really ought to give me a raise for this. Oh well...","TWN":"這也是一種職業病了，要是職業病能獲得承認就好了。唉～"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그럼 전 이만. 바쁘신데 실례했어요.","JPN":"じゃあ、私はこれで。お忙しいところ、失礼しました。","ENG":"Anyway, I’ll get out of your hair now. Sorry to disturb you.","TWN":"那我就先走了。抱歉打擾大家囉。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어, 어디로 가는 거에요?","JPN":"ど、どこへ行くんですか？","ENG":"W-where are you going?","TWN":"妳、妳要去哪裡？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그야...... 용의자가 나타날 만한 곳으로요.","JPN":"そりゃ……容疑者の現れそうなところです。","ENG":"Well... Wherever the suspect is most likely to appear, of course.","TWN":"當然是……嫌疑人會出現的地方囉。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};